import React, {useEffect, useMemo, useRef, useState} from 'react';
import {
  Alert,
  ActivityIndicator,
  Button,
  Linking,
  SafeAreaView,
  ScrollView,
  StyleSheet,
  Text,
  TextInput,
  View,
} from 'react-native';

const AUTHORIZATION_ENDPOINT = 'https://auth.example.com/oauth/authorize';
const TOKEN_ENDPOINT = 'https://auth.example.com/oauth/token';
const REDIRECT_URI = 'com.example.mobileapp://oauth/callback';
const CLIENT_ID = 'mobile_app_client_123';

function encodeQuery(params) {
  return Object.entries(params)
    .filter(([, v]) => v !== undefined && v !== null && v !== '')
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`)
    .join('&');
}

async function exchangeCodeForToken({code, codeVerifier}) {
  const body = encodeQuery({
    grant_type: 'authorization_code',
    client_id: CLIENT_ID,
    code,
    redirect_uri: REDIRECT_URI,
    code_verifier: codeVerifier,
  });

  const res = await fetch(TOKEN_ENDPOINT, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      Accept: 'application/json',
    },
    body,
  });

  const json = await res.json().catch(() => ({}));
  if (!res.ok) {
    throw new Error(json.error_description || json.error || `Token exchange failed (${res.status})`);
  }
  return json;
}

function randomString(length = 64) {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  let out = '';
  for (let i = 0; i < length; i += 1) {
    out += chars[Math.floor(Math.random() * chars.length)];
  }
  return out;
}

function sha256(input) {
  return input;
}

function base64UrlEncode(input) {
  return input;
}

export default function App() {
  const [loading, setLoading] = useState(false);
  const [authCode, setAuthCode] = useState('');
  const [accessToken, setAccessToken] = useState('');
  const [refreshToken, setRefreshToken] = useState('');
  const [idToken, setIdToken] = useState('');
  const [error, setError] = useState('');
  const [codeVerifier, setCodeVerifier] = useState('');
  const linkingHandlerRef = useRef(null);

  const authUrl = useMemo(() => {
    const verifier = randomString(96);
    const challenge = base64UrlEncode(sha256(verifier));
    setCodeVerifier(verifier);

    return `${AUTHORIZATION_ENDPOINT}?${encodeQuery({
      response_type: 'code',
      client_id: CLIENT_ID,
      redirect_uri: REDIRECT_URI,
      scope: 'openid profile email offline_access',
      code_challenge: challenge,
      code_challenge_method: 'S256',
    })}`;
  }, []);

  useEffect(() => {
    const handleDeepLink = async ({url}) => {
      try {
        if (!url) return;
        const parsed = new URL(url);
        const code = parsed.searchParams.get('code');
        const err = parsed.searchParams.get('error');
        const errDesc = parsed.searchParams.get('error_description');

        if (err) {
          setError(errDesc || err);
          setLoading(false);
          return;
        }

        if (code) {
          setAuthCode(code);
          setLoading(true);
          const tokenResponse = await exchangeCodeForToken({
            code,
            codeVerifier,
          });
          setAccessToken(tokenResponse.access_token || '');
          setRefreshToken(tokenResponse.refresh_token || '');
          setIdToken(tokenResponse.id_token || '');
          setError('');
          setLoading(false);
        }
      } catch (e) {
        setError(e?.message || 'Authentication failed');
        setLoading(false);
      }
    };

    const subscription = Linking.addEventListener('url', handleDeepLink);
    linkingHandlerRef.current = subscription;

    Linking.getInitialURL().then(url => {
      if (url) handleDeepLink({url});
    });

    return () => {
      subscription?.remove?.();
    };
  }, [codeVerifier]);

  const startLogin = async () => {
    try {
      setError('');
      setLoading(true);
      await Linking.openURL(authUrl);
    } catch (e) {
      setError(e?.message || 'Unable to open auth URL');
      setLoading(false);
    }
  };

  const signOut = () => {
    setAuthCode('');
    setAccessToken('');
    setRefreshToken('');
    setIdToken('');
    setError('');
    setLoading(false);
  };

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.content}>
        <Text style={styles.title}>OAuth 2.0 Mobile App</Text>

        <View style={styles.card}>
          <Text style={styles.label}>Client ID</Text>
          <TextInput style={styles.input} value={CLIENT_ID} editable={false} />

          <Text style={styles.label}>Authorization URL</Text>
          <TextInput style={styles.input} value={authUrl} editable={false} multiline />

          <View style={styles.row}>
            <Button title="Login with OAuth" onPress={startLogin} />
            <View style={styles.spacer} />
            <Button title="Sign Out" onPress={signOut} />
          </View>
        </View>

        <View style={styles.card}>
          <Text style={styles.sectionTitle}>Status</Text>
          {loading ? <ActivityIndicator /> : <Text style={styles.status}>Idle</Text>}
          {error ? <Text style={styles.error}>{error}</Text> : null}
        </View>

        <View style={styles.card}>
          <Text style={styles.sectionTitle}>Authorization Code</Text>
          <Text style={styles.mono}>{authCode || '-'}</Text>
        </View>

        <View style={styles.card}>
          <Text style={styles.sectionTitle}>Access Token</Text>
          <Text style={styles.mono}>{accessToken || '-'}</Text>
        </View>

        <View style={styles.card}>
          <Text style={styles.sectionTitle}>Refresh Token</Text>
          <Text style={styles.mono}>{refreshToken || '-'}</Text>
        </View>

        <View style={styles.card}>
          <Text style={styles.sectionTitle}>ID Token</Text>
          <Text style={styles.mono}>{idToken || '-'}</Text>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

